<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0" />
  <title>2048</title>
  <style>
    :root {
      color-scheme: dark;
    }

    * {
      box-sizing: border-box;
    }

    body {
      margin: 0;
      min-height: 100vh;
      display: grid;
      place-items: center;
      background: #12151c;
      color: #f7f3ea;
      font-family: Arial, Helvetica, sans-serif;
    }

    .game-wrap {
      width: min(92vw, 500px);
      padding: 20px;
    }

    .topbar {
      display: flex;
      align-items: center;
      justify-content: space-between;
      gap: 14px;
      margin-bottom: 16px;
    }

    h1 {
      margin: 0;
      font-size: clamp(2.2rem, 8vw, 4rem);
      letter-spacing: -0.08em;
      color: #f2b179;
    }

    .controls {
      display: flex;
      align-items: center;
      gap: 10px;
    }

    .score-box {
      min-width: 88px;
      padding: 8px 12px;
      border-radius: 8px;
      text-align: center;
      background: #303744;
      color: #aeb6c5;
      font-size: 0.68rem;
      font-weight: bold;
      letter-spacing: 0.08em;
      text-transform: uppercase;
    }

    #score {
      display: block;
      margin-top: 3px;
      color: white;
      font-size: 1.35rem;
      letter-spacing: 0;
    }

    #reset {
      border: 0;
      border-radius: 8px;
      padding: 12px 14px;
      background: #f2b179;
      color: #25211d;
      font: inherit;
      font-weight: bold;
      cursor: pointer;
      transition: transform 0.12s ease, background 0.12s ease;
    }

    #reset:hover {
      background: #f5c38f;
    }

    #reset:active {
      transform: scale(0.96);
    }

    .hint {
      margin: 0 0 12px;
      color: #9ca5b6;
      font-size: 0.92rem;
    }

    #board {
      display: grid;
      grid-template-columns: repeat(4, 1fr);
      gap: 10px;
      width: 100%;
      aspect-ratio: 1;
      padding: 10px;
      border-radius: 13px;
      background: #303744;
      box-shadow: 0 18px 50px rgba(0, 0, 0, 0.35);
    }

    .tile {
      display: flex;
      align-items: center;
      justify-content: center;
      min-width: 0;
      border-radius: 8px;
      background: #444c5c;
      color: #d5d9e1;
      font-size: clamp(1.2rem, 8vw, 2.7rem);
      font-weight: 800;
      line-height: 1;
      user-select: none;
    }

    .tile[data-value="2"] { background: #eee4da; color: #3d3a35; }
    .tile[data-value="4"] { background: #ede0c8; color: #3d3a35; }
    .tile[data-value="8"] { background: #f2b179; color: #fff; }
    .tile[data-value="16"] { background: #f59563; color: #fff; }
    .tile[data-value="32"] { background: #f67c5f; color: #fff; }
    .tile[data-value="64"] { background: #f65e3b; color: #fff; }
    .tile[data-value="128"] { background: #edcf72; color: #fff; font-size: clamp(1rem, 6.5vw, 2.2rem); }
    .tile[data-value="256"] { background: #edcc61; color: #fff; font-size: clamp(1rem, 6.5vw, 2.2rem); }
    .tile[data-value="512"] { background: #edc850; color: #fff; font-size: clamp(1rem, 6.5vw, 2.2rem); }
    .tile[data-value="1024"] { background: #edc53f; color: #fff; font-size: clamp(0.85rem, 5.5vw, 1.8rem); }
    .tile[data-value="2048"] { background: #edc22e; color: #fff; font-size: clamp(0.85rem, 5.5vw, 1.8rem); }
    .tile[data-value="4096"],
    .tile[data-value="8192"] {
      background: #8f7a66;
      color: #fff;
      font-size: clamp(0.8rem, 5vw, 1.6rem);
    }
  </style>
</head>
<body>
  <main class="game-wrap">
    <div class="topbar">
      <h1>2048</h1>
      <div class="controls">
        <div class="score-box">
          Score
          <span id="score">0</span>
        </div>
        <button id="reset" type="button">New Game</button>
      </div>
    </div>

    <p class="hint">Use the arrow keys to move and combine tiles.</p>
    <div id="board" aria-label="2048 game board"></div>
  </main>

  <script>
    (function () {
      const SIZE = 4;
      const boardElement = document.getElementById("board");
      const scoreElement = document.getElementById("score");
      const resetButton = document.getElementById("reset");

      let grid = [];
      let currentScore = 0;

      function makeEmptyBoard() {
        return Array.from({ length: SIZE }, () => Array(SIZE).fill(0));
      }

      function render() {
        boardElement.innerHTML = "";

        for (let row = 0; row < SIZE; row++) {
          for (let col = 0; col < SIZE; col++) {
            const value = grid[row][col];
            const tile = document.createElement("div");
            tile.className = "tile";
            tile.dataset.value = value;
            tile.textContent = value === 0 ? "" : value;
            tile.setAttribute("aria-label", value === 0 ? "Empty" : String(value));
            boardElement.appendChild(tile);
          }
        }

        scoreElement.textContent = currentScore;
      }

      function emptyCells() {
        const cells = [];
        for (let row = 0; row < SIZE; row++) {
          for (let col = 0; col < SIZE; col++) {
            if (grid[row][col] === 0) cells.push([row, col]);
          }
        }
        return cells;
      }

      function spawnTile() {
        const cells = emptyCells();
        if (cells.length === 0) return false;

        const [row, col] = cells[Math.floor(Math.random() * cells.length)];
        grid[row][col] = Math.random() < 0.9 ? 2 : 4;
        return true;
      }

      function collapseLine(line) {
        const values = line.filter(value => value !== 0);
        const result = [];

        for (let i = 0; i < values.length; i++) {
          if (i + 1 < values.length && values[i] === values[i + 1]) {
            const merged = values[i] * 2;
            result.push(merged);
            currentScore += merged;
            i++;
          } else {
            result.push(values[i]);
          }
        }

        while (result.length < SIZE) result.push(0);
        return result;
      }

      function move(direction) {
        if (!["left", "right", "up", "down"].includes(direction)) {
          return false;
        }

        const before = grid.map(row => row.slice());

        if (direction === "left" || direction === "right") {
          for (let row = 0; row < SIZE; row++) {
            let line = grid[row].slice();
            if (direction === "right") line.reverse();

            line = collapseLine(line);

            if (direction === "right") line.reverse();
            grid[row] = line;
          }
        } else {
          for (let col = 0; col < SIZE; col++) {
            let line = [];
            for (let row = 0; row < SIZE; row++) line.push(grid[row][col]);

            if (direction === "down") line.reverse();
            line = collapseLine(line);
            if (direction === "down") line.reverse();

            for (let row = 0; row < SIZE; row++) grid[row][col] = line[row];
          }
        }

        let changed = false;
        for (let row = 0; row < SIZE; row++) {
          for (let col = 0; col < SIZE; col++) {
            if (grid[row][col] !== before[row][col]) {
              changed = true;
              break;
            }
          }
          if (changed) break;
        }

        if (changed) spawnTile();
        else {
          /* No merge can occur without changing board position/value.
             Restore score in case of any unexpected no-change scenario. */
          let oldScore = currentScore;
          let potentialScore = 0;
          for (let row = 0; row < SIZE; row++) {
            for (let col = 0; col < SIZE; col++) {
              if (before[row][col] !== grid[row][col]) potentialScore++;
            }
          }
          if (potentialScore === 0) currentScore = oldScore;
        }

        render();
        return changed;
      }

      function reset() {
        grid = makeEmptyBoard();
        currentScore = 0;
        spawnTile();
        spawnTile();
        render();
      }

      function setBoard(arr) {
        if (!Array.isArray(arr) || arr.length !== SIZE ||
            arr.some(row => !Array.isArray(row) || row.length !== SIZE)) {
          throw new Error("setBoard expects a 4x4 array.");
        }

        grid = arr.map(row => row.map(value => {
          const number = Number(value);
          return Number.isFinite(number) ? number : 0;
        }));
        render();
      }

      window.game = {
        size: SIZE,
        reset,
        move,
        board: function () {
          return grid.map(row => row.slice());
        },
        setBoard,
        score: function () {
          return currentScore;
        }
      };

      resetButton.addEventListener("click", reset);

      window.addEventListener("keydown", function (event) {
        const keyMap = {
          ArrowLeft: "left",
          ArrowRight: "right",
          ArrowUp: "up",
          ArrowDown: "down"
        };

        if (keyMap[event.key]) {
          event.preventDefault();
          move(keyMap[event.key]);
        }
      });

      reset();
    })();
  </script>
</body>
</html>
